package cmd

import (
	"encoding/json"
	"fmt"
	"path/filepath"

	"github.com/DocumentDrivenDX/ddx/internal/agent"
	"github.com/DocumentDrivenDX/ddx/internal/bead"
	"github.com/DocumentDrivenDX/ddx/internal/ddxroot"
	"github.com/spf13/cobra"
)

// newBeadDoctorCommand wires `ddx bead doctor` / `ddx bead doctor --fix`.
//
// Scan mode (no flags): exits non-zero if any field on any bead exceeds the
// per-field cap (ddx-f8a11202), reporting the offending bead id, field, and
// size. Safe to run on any tree — no mutations.
//
// Fix mode (--fix): rewrites oversized fields in place. Before touching the
// tracker the command writes a timestamped backup under .ddx/backups/ so
// the original file is always recoverable. Overflow content persists as
// artifacts under .ddx/executions/<bead-id>/repair-<timestamp>/ and a
// repair event is appended to each rewritten bead. Idempotent — the second
// invocation exits 0 without writing because the scan is clean.
//
// Dangling-success mode (--dangling): detects in_progress beads whose last
// execution produced task_succeeded but CloseWithEvidence never ran. Safe
// to run on any tree — no mutations unless --fix is also passed.
// (ddx-2b2d114e)
func (f *CommandFactory) newBeadDoctorCommand() *cobra.Command {
	cmd := &cobra.Command{
		Use:   "doctor",
		Short: "Detect (and optionally repair) beads.jsonl rows with oversized fields",
		Long: `Scan the bead tracker for fields that exceed the per-field size cap.

Bead fields (description, acceptance, notes, events[].body, events[].summary)
are capped at 65,535 bytes so DDx-authored beads round-trip cleanly through
bd import (upstream's Dolt TEXT column limit). Fields over the cap usually
come from a writer bug that landed before the cap was enforced — for
example a reviewer stream dumped verbatim into an event body.

Without --fix this command only reports offending rows and exits non-zero.
With --fix it:

  1. Writes a timestamped backup to .ddx/backups/ before any mutation.
  2. Truncates each oversized field to the cap using head+tail+marker.
  3. Writes the full original payload to
     .ddx/executions/<bead>/repair-<timestamp>/<field>.log so forensics
     remain possible.
  4. Appends a kind=repair event to every rewritten bead.

Idempotent: once a tracker is clean, running --fix again is a no-op.

With --dangling: scan for in_progress beads whose last execution produced
task_succeeded but whose bead-close step never ran (dangling-success).
For each finding, reports whether result_rev is reachable from HEAD:
  - reachable=true:  merge succeeded, close didn't. Safe to close manually
    with: ddx bead close <bead-id>
  - reachable=false: the merge itself was never applied (dangling commit).
    The result_rev is shown for manual git cherry-pick or re-attempt.
(ddx-2b2d114e)`,
		RunE: func(cmd *cobra.Command, args []string) error {
			workspace := f.beadWorkspaceRoot()
			if workspace == "" {
				return fmt.Errorf("bead doctor: no .ddx workspace found")
			}
			path := ddxroot.JoinProject(workspace, "beads.jsonl")

			doFix, _ := cmd.Flags().GetBool("fix")
			asJSON, _ := cmd.Flags().GetBool("json")
			doDangling, _ := cmd.Flags().GetBool("dangling")

			// --dangling mode: detect dangling-success beads (ddx-2b2d114e).
			if doDangling {
				findings, err := agent.DetectDanglingSuccessBeads(workspace)
				if err != nil {
					return fmt.Errorf("bead doctor --dangling: %w", err)
				}
				if asJSON {
					enc := json.NewEncoder(cmd.OutOrStdout())
					enc.SetIndent("", "  ")
					return enc.Encode(struct {
						Clean    bool                           `json:"clean"`
						Findings []agent.DanglingSuccessFinding `json:"findings"`
					}{
						Clean:    len(findings) == 0,
						Findings: findings,
					})
				}
				out := cmd.OutOrStdout()
				if len(findings) == 0 {
					fmt.Fprintf(out, "bead doctor --dangling: clean (no dangling-success beads detected)\n")
					return nil
				}
				fmt.Fprintf(out, "bead doctor --dangling: %d finding(s):\n", len(findings))
				for _, fi := range findings {
					reachableStr := "reachable=false (dangling commit — merge never applied)"
					recovery := "  recovery: git cherry-pick or re-run ddx try " + fi.BeadID
					if fi.Reachable {
						reachableStr = "reachable=true (merge succeeded, close didn't run)"
						recovery = "  recovery: ddx bead close " + fi.BeadID + "  # or re-run ddx try"
					}
					fmt.Fprintf(out, "  %s  attempt=%s  result_rev=%s\n    %s\n%s\n",
						fi.BeadID, fi.AttemptID, fi.ResultRev, reachableStr, recovery)
				}
				return fmt.Errorf("bead doctor --dangling: %d finding(s) detected", len(findings))
			}

			var report bead.DoctorReport
			var err error
			if doFix {
				report, err = bead.BeadDoctorFix(path, nil)
			} else {
				report, err = bead.BeadDoctor(path)
			}
			if err != nil {
				return err
			}

			if asJSON {
				enc := json.NewEncoder(cmd.OutOrStdout())
				enc.SetIndent("", "  ")
				return enc.Encode(struct {
					Path     string               `json:"path"`
					Fixed    bool                 `json:"fixed"`
					Clean    bool                 `json:"clean"`
					Findings []bead.DoctorFinding `json:"findings"`
				}{
					Path:     report.Path,
					Fixed:    doFix && !report.Clean(),
					Clean:    report.Clean(),
					Findings: report.Findings,
				})
			}

			out := cmd.OutOrStdout()
			if report.Clean() {
				fmt.Fprintf(out, "bead doctor: %s — clean (no fields exceed %d bytes)\n", path, bead.MaxFieldBytes)
				return nil
			}
			fmt.Fprintf(out, "bead doctor: %s — %d finding(s) exceeding %d-byte cap:\n", path, len(report.Findings), bead.MaxFieldBytes)
			for _, f := range report.Findings {
				fmt.Fprintf(out, "  %s  %s  %d bytes  head=%q\n", f.BeadID, f.FieldPath, f.SizeBytes, f.SampleHead)
			}
			if doFix {
				fmt.Fprintf(out, "\nrepair complete. backup written to %s/backups/. artifact sidecars under %s/executions/<bead>/repair-*/\n", filepath.Dir(path), filepath.Dir(path))
				return nil
			}
			// Non-fix scan: non-zero exit via cobra error so CI can catch it.
			return fmt.Errorf("bead doctor: %d finding(s) — run `ddx bead doctor --fix` to repair", len(report.Findings))
		},
	}
	cmd.Flags().Bool("fix", false, "Rewrite oversized fields in place after writing a backup")
	cmd.Flags().Bool("json", false, "Output findings as JSON")
	cmd.Flags().Bool("dangling", false, "Detect in_progress beads with a prior task_succeeded result (dangling-success, ddx-2b2d114e)")
	return cmd
}

package bead

import (
	"fmt"
	"strings"
	"time"
)

// Bead represents a portable work item with metadata.
// The schema matches bd/br JSONL format for interchange compatibility.
// Unknown fields from external sources are preserved in Extra.
type Bead struct {
	ID            string    `json:"id"`
	Title         string    `json:"title"`
	Status        string    `json:"status"`
	Priority      int       `json:"priority"`
	IssueType     string    `json:"issue_type"`
	SchemaVersion int       `json:"schema_version"`
	Owner         string    `json:"owner,omitempty"`
	CreatedAt     time.Time `json:"created_at"`
	CreatedBy     string    `json:"created_by,omitempty"`
	UpdatedAt     time.Time `json:"updated_at"`

	// Optional fields (bd-compatible)
	Labels      []string `json:"labels,omitempty"`
	Parent      string   `json:"parent,omitempty"`
	Description string   `json:"description,omitempty"`
	Acceptance  string   `json:"acceptance,omitempty"`
	Notes       string   `json:"notes,omitempty"`

	// Dependencies use bd-compatible format
	Dependencies []Dependency `json:"dependencies,omitempty"`

	// Extra holds unknown fields for round-trip preservation.
	// Workflow-specific fields (e.g. HELIX spec-id, execution-eligible)
	// are stored here and written back on save.
	Extra map[string]any `json:"-"`
}

// Dependency represents a link between two beads (bd-compatible format).
type Dependency struct {
	IssueID     string `json:"issue_id"`
	DependsOnID string `json:"depends_on_id"`
	Type        string `json:"type"` // "blocks", "related", etc.
	CreatedAt   string `json:"created_at,omitempty"`
	CreatedBy   string `json:"created_by,omitempty"`
	Metadata    string `json:"metadata,omitempty"`
}

// BeadEvent records append-only execution evidence.
type BeadEvent struct {
	Kind      string    `json:"kind"`
	Summary   string    `json:"summary,omitempty"`
	Body      string    `json:"body,omitempty"`
	Actor     string    `json:"actor,omitempty"`
	CreatedAt time.Time `json:"created_at"`
	Source    string    `json:"source,omitempty"`
}

// Status constants
const (
	StatusOpen       = "open"
	StatusInProgress = "in_progress"
	StatusClosed     = "closed"
	// StatusBlocked marks an explicit external blocker that can be rechecked.
	// Dependency waits are derived from dependency status and do not persist as
	// blocked.
	StatusBlocked = "blocked"
	// StatusProposed marks work awaiting operator approval or clarification.
	// It is outside worker dispatch until transitioned to open or cancelled.
	StatusProposed = "proposed"
	// StatusCancelled marks work that will not run and does not satisfy
	// dependents.
	StatusCancelled = "cancelled"
)

// CanonicalStatuses is the single source of truth for the persisted bead
// status enumeration. It mirrors the bd/br canonical set documented in
// TD-031 §2 and the JSON Schema enum at
// cli/internal/bead/schema/bead-record.schema.json. The CI guard tests in
// sync_test.go assert that schema, TD doc, and Go source agree with this
// list; adding or removing a value here without updating the schema and TD
// will fail CI.
var CanonicalStatuses = []string{
	StatusOpen,
	StatusInProgress,
	StatusClosed,
	StatusBlocked,
	StatusProposed,
	StatusCancelled,
}

// IsCanonicalStatus reports whether s is one of the persisted bead statuses
// in CanonicalStatuses.
func IsCanonicalStatus(s string) bool {
	for _, c := range CanonicalStatuses {
		if c == s {
			return true
		}
	}
	return false
}

// IssueType constants
const (
	// IssueTypeOperatorPrompt is the bead type used for operator-submitted
	// prompts that the work runs as instructions.
	IssueTypeOperatorPrompt = "operator-prompt"
	// IssueTypeReviewFinding is a bead kind for findings produced by review engines.
	// Parent must reference the bead under review.
	IssueTypeReviewFinding = "review-finding"
	// IssueTypeAlignmentReview is a bead kind for alignment review work.
	// Parent must reference the bead under alignment.
	IssueTypeAlignmentReview = "alignment-review"
)

// Default labels and other defaults for operator-prompt beads.
const (
	OperatorPromptLabelKind   = "kind:operator-prompt"
	OperatorPromptLabelSource = "source:web-ui"
	// OperatorPromptDefaultAcceptance is the auto-AC stub used when an
	// operator submits a prompt without explicit acceptance criteria. The
	// structural AC verifier is skipped for operator-prompt beads, so this
	// stub stands as a human-readable contract only.
	OperatorPromptDefaultAcceptance = "Agent must produce a diff or no_changes rationale; the prompt body is the contract."
)

// OperatorPromptMutationGuard enforces the no-self-mutation rule from
// Story 15: an operator-prompt bead's execution may not create, edit, or
// close another operator-prompt bead. The guard returns nil when the
// mutation is allowed and a non-nil error when it must be rejected.
//
// actorIssueType is the issue_type of the bead currently being executed
// (empty when no operator-prompt context is active). targetIssueType is
// the issue_type of the bead about to be mutated.
//
// Allow/deny matrix:
//
//	actor=""               , target=*                → allow
//	actor="task"           , target=*                → allow
//	actor="operator-prompt", target!="operator-prompt" → allow
//	actor="operator-prompt", target=="operator-prompt" → deny
func OperatorPromptMutationGuard(actorIssueType, targetIssueType string) error {
	if actorIssueType != IssueTypeOperatorPrompt {
		return nil
	}
	if targetIssueType != IssueTypeOperatorPrompt {
		return nil
	}
	return fmt.Errorf("bead: operator-prompt bead may not mutate another operator-prompt bead")
}

// NewOperatorPromptBead constructs a fresh operator-prompt bead from a raw
// prompt string, applying the Story 15 template defaults: title is the first
// non-empty line of the prompt, full prompt body is preserved verbatim in the
// description, default labels are kind:operator-prompt + source:web-ui, the
// status starts in `proposed` (approval flow), priority defaults to the
// caller-supplied priority (clamped to MinPriority..MaxPriority), and the
// acceptance field carries the auto-AC stub.
//
// The returned bead is not persisted; callers feed it to Store.Create which
// will assign the ID and CreatedAt/UpdatedAt timestamps.
func NewOperatorPromptBead(prompt string, defaultTier int) *Bead {
	body := strings.TrimSpace(prompt)
	title := body
	if i := strings.IndexByte(body, '\n'); i >= 0 {
		title = strings.TrimSpace(body[:i])
	}
	if title == "" {
		title = "(empty operator prompt)"
	}
	priority := defaultTier
	if priority < MinPriority {
		priority = MinPriority
	}
	if priority > MaxPriority {
		priority = MaxPriority
	}
	return &Bead{
		Title:       title,
		IssueType:   IssueTypeOperatorPrompt,
		Status:      StatusProposed,
		Priority:    priority,
		Labels:      []string{OperatorPromptLabelKind, OperatorPromptLabelSource},
		Description: body,
		Acceptance:  OperatorPromptDefaultAcceptance,
	}
}

// Default values
const (
	DefaultType          = "task"
	DefaultStatus        = StatusOpen
	DefaultPriority      = 2
	DefaultPrefix        = "bx" // used only when repo name detection fails
	CurrentSchemaVersion = 1
	MinPriority          = 0
	MaxPriority          = 4
)

// StatusCounts holds aggregate counts for a bead store.
type StatusCounts struct {
	Open              int `json:"open"`
	InProgress        int `json:"in_progress"`
	Closed            int `json:"closed"`
	Blocked           int `json:"blocked"`
	Proposed          int `json:"proposed"`
	Cancelled         int `json:"cancelled"`
	Ready             int `json:"ready"`
	NeedsHuman        int `json:"needs_human"`
	WorkerReady       int `json:"worker_ready"`
	DependencyWaiting int `json:"dependency_waiting"`
	ExternalBlocked   int `json:"external_blocked"`
	OperatorAttention int `json:"operator_attention"`
	Total             int `json:"total"`
}

// Blocker kinds surfaced through BlockedAll. These strings are part of the
// external DDx contract (HELIX reads them to decide how to handle a blocker).
const (
	BlockerKindDependency         = "dependency"
	BlockerKindBlockedStatus      = "blocked-status"
	BlockerKindRetryCooldown      = "retry-cooldown"
	BlockerKindNeedsInvestigation = "needs-investigation"
	BlockerKindOperatorAttention  = "operator-attention"
	BlockerKindNotEligible        = "not-execution-eligible"
	BlockerKindSuperseded         = "superseded"
	BlockerKindEpicOnly           = "epic-only"
)

// Blocker describes why an open bead is currently not runnable. Either
// unclosed dependencies exist, or an work cooldown has parked the
