_to_id.get(collection) {\\n41\\t            return id;\\n42\\t        }\\n43\\t        self.next_id += 1;\\n44\\t        let id = self.next_id;\\n45\\t        self.name_to_id.insert(collection.clone(), id);\\n46\\t        self.id_to_name.insert(id, collection.clone());\\n47\\t        id\\n48\\t    }\\n49\\t\\n50\\t    fn remove(\u0026mut self, collection: \u0026CatalogKey) {\\n51\\t        if let Some(id) = self.name_to_id.remove(collection) {\\n52\\t            self.id_to_name.remove(\u0026id);\\n53\\t        }\\n54\\t    }\\n55\\t}\\n56\\t\\n57\\t/// Key for the dedicated link store: (source_col, source_id, link_type, target_col, target_id).\\n58\\ttype LinkKey = (CollectionId, EntityId, String, CollectionId, EntityId);\\n59\\t\\n60\\t/// Combined snapshot of mutable state captured at transaction start.\\n61\\t#[derive(Debug, Clone)]\\n62\\tstruct TxSnapshot {\\n63\\t    data: HashMap\u003cCatalogKey, CollectionMap\u003e,\\n64\\t    schema_versions: HashMap\u003cCatalogKey, BTreeMap\u003cu32, SchemaVersionEntry\u003e\u003e,\\n65\\t    collection_views: HashMap\u003cCatalogKey, CollectionViewEntry\u003e,\\n66\\t    collections: HashSet\u003cCatalogKey\u003e,\\n67\\t    databases: BTreeSet\u003cString\u003e,\\n68\\t    namespaces: BTreeMap\u003cString, BTreeSet\u003cString\u003e\u003e,\\n69\\t    /// Index snapshot for rollback.\\n70\\t    indexes: BTreeMap\u003cIndexKey, BTreeSet\u003cEntityId\u003e\u003e,\\n71\\t    /// Compound index snapshot for rollback.\\n72\\t    compound_indexes: BTreeMap\u003cCompoundIndexKey, BTreeSet\u003cEntityId\u003e\u003e,\\n73\\t    /// Numeric ID cache snapshot for rollback.\\n74\\t    numeric_ids: NumericIdCache,\\n75\\t    /// Dedicated link store snapshot.\\n76\\t    links: BTreeMap\u003cLinkKey, Link\u003e,\\n77\\t}\\n78\\t\\n79\\t/// In-memory storage adapter for testing and development.\\n80\\t///\\n81\\t/// All data is lost when the adapter is dropped.\\n82\\t///\\n83\\t/// Transactions use a full-snapshot approach: [`begin_tx`] captures a clone of\\n84\\t/// the current state; [`abort_tx`] restores it; [`commit_tx`] discards the\\n85\\t/// snapshot. Because all mutations require `\u0026mut self`, Rust's borrow checker\\n86\\t/// already provides exclusive access, so no additional synchronisation is\\n87\\t/// needed.\\n88\\t#[derive(Debug)]\\n89\\tpub struct MemoryStorageAdapter {\\n90\\t    data: HashMap\u003cCatalogKey, CollectionMap\u003e,\\n91\\t    /// Schema version history keyed by (collection → version → schema).\\n92\\t    schema_versions: HashMap\u003cCatalogKey, BTreeMap\u003cu32, SchemaVersionEntry\u003e\u003e,\\n93\\t    /// Latest collection view keyed by collection.\\n94\\t    collection_views: HashMap\u003cCatalogKey, CollectionViewEntry\u003e,\\n95\\t    /// Explicitly registered collections.\\n96\\t    collections: HashSet\u003cCatalogKey\u003e,\\n97\\t    /// Known database names.\\n98\\t    databases: BTreeSet\u003cString\u003e,\\n99\\t    /// Database -\u003e schema names.\\n100\\t    namespaces: BTreeMap\u003cString, BTreeSet\u003cString\u003e\u003e,\\n101\\t    /// Snapshot saved at `begin_tx`; `Some` means a transaction is active.\\n102\\t    tx_snapshot: Option\u003cTxSnapshot\u003e,\\n103\\t    /// EAV secondary index: (collection, field, value) → set of entity IDs.\\n104\\t    indexes: BTreeMap\u003cIndexKey, BTreeSet\u003cEntityId\u003e\u003e,\\n105\\t    /// Compound indexes: (collection, index_position, compound_key) → set of entity IDs.\\n106\\t    compound_indexes: BTreeMap\u003cCompoundIndexKey, BTreeSet\u003cEntityId\u003e\u003e,\\n107\\t    /// Bidirectional name-to-numeric-ID cache (ADR-010).\\n108\\t    numeric_ids: NumericIdCache,\\n109\\t    /// Dedicated link store (ADR-010): replaces __axon_links__ pseudo-collection\\n110\\t    /// for new code paths. Keyed by (source_col, source_id, link_type, target_col, target_id).\\n111\\t    links: BTreeMap\u003cLinkKey, Link\u003e,\\n112\\t}\\n113\\t\\n114\\tfn now_ns() -\u003e u64 {\\n115\\t    SystemTime::now()\\n116\\t        .duration_since(UNIX_EPOCH)\\n117\\t        .unwrap_or_default()\\n118\\t        .as_nanos() as u64\\n119\\t}\\n120\\t\\n121\\tfn unregistered_collection_error(collection: \u0026CollectionId) -\u003e AxonError {\\n122\\t    AxonError::InvalidArgument(format!(\\n123\\t        \\\"collection '{}' is not registered\\\",\\n124\\t        collection.as_str()\\n125\\t    ))\\n126\\t}\\n127\\t\\n128\\timpl Default for MemoryStorageAdapter {\\n129\\t    fn default() -\u003e Self {\\n130\\t        let mut databases = BTreeSet::new();\\n131\\t        databases.insert(DEFAULT_DATABASE.to_string());\\n132\\t\\n133\\t        let mut namespaces = BTreeMap::new();\\n134\\t        namespaces.insert(\\n135\\t            DEFAULT_DATABASE.to_string(),\\n136\\t            BTreeSet::from([DEFAULT_SCHEMA.to_string()]),\\n137\\t        );\\n138\\t\\n139\\t        Self {\\n140\\t            data: HashMap::new(),\\n141\\t            schema_versions: HashMap::new(),\\n142\\t            collection_views: HashMap::new(),\\n143\\t            collections: HashSet::new(),\\n144\\t            databases,\\n145\\t            namespaces,\\n146\\t            tx_snapshot: None,\\n147\\t            indexes: BTreeMap::new(),\\n148\\t            compound_indexes: BTreeMap::new(),\\n149\\t            numeric_ids: NumericIdCache::default(),\\n150\\t            links: BTreeMap::new(),\\n151\\t        }\\n152\\t    }\\n153\\t}\\n154\\t\\n155\\timpl MemoryStorageAdapter {\\n156\\t    fn catalog_key(namespace: \u0026Namespace, collection: \u0026CollectionId) -\u003e CatalogKey {\\n157\\t        CatalogKey::from_parts(namespace, collection)\\n158\\t    }\\n159\\t\\n160\\t    fn registered_catalog_keys(\u0026self, collection: \u0026CollectionId) -\u003e Vec\u003cCatalogKey\u003e {\\n161\\t        let mut keys: Vec\u003c_\u003e = self\\n162\\t            .collections\\n163\\t            .iter()\\n164\\t            .filter(|key| key.collection == *collection)\\n165\\t            .cloned()\\n166\\t            .collect();\\n167\\t        keys.sort();\\n168\\t        keys\\n169\\t    }\\n170\\t\\n171\\t    fn resolve_catalog_key(\u0026self, collection: \u0026CollectionId) -\u003e Result\u003cCatalogKey, AxonError\u003e {\\n172\\t        let (namespace, bare_collection) = Namespace::parse(collection.as_str());\\n173\\t        if bare_collection != collection.as_str() {\\n174\\t            return Ok(Self::catalog_key(\\n175\\t                \u0026namespace,\\n176\\t                \u0026CollectionId::new(bare_collection),\\n177\\t            ));\\n178\\t        }\\n179\\t\\n180\\t        let keys = self.registered_catalog_keys(collection);\\n181\\t        match keys.as_slice() {\\n182\\t            [] =\u003e Ok(Self::catalog_key(\u0026Namespace::default_ns(), collection)),\\n183\\t            [key] =\u003e Ok(key.clone()),\\n184\\t            _ =\u003e {\\n185\\t                let default_key = Self::catalog_key(\u0026Namespace::default_ns(), collection);\\n186\\t                if keys.contains(\u0026default_key) {\\n187\\t                    Ok(default_key)\\n188\\t                } else {\\n189\\t                    Err(AxonError::InvalidArgument(format!(\\n190\\t                        \\\"collection '{}' exists in multiple namespaces; qualify the namespace\\\",\\n191\\t                        collection.as_str()\\n192\\t                    )))\\n193\\t                }\\n194\\t            }\\n195\\t        }\\n196\\t    }\\n197\\t\\n198\\t    fn remove_catalog_key(\u0026mut self, key: \u0026CatalogKey) {\\n199\\t        self.collections.remove(key);\\n200\\t        self.schema_versions.remove(key);\\n201\\t        self.collection_views.remove(key);\\n202\\t        self.numeric_ids.remove(key);\\n203\\t        self.indexes\\n204\\t            .retain(|(collection, _, _), _| collection != key);\\n205\\t        self.compound_indexes\\n206\\t            .retain(|(collection, _, _), _| collection != key);\\n207\\t    }\\n208\\t\\n209\\t    fn purge_collection_entities(\u0026mut self, collection: \u0026CatalogKey) {\\n210\\t        self.data.remove(collection);\\n211\\t    }\\n212\\t\\n213\\t    fn purge_doomed_collection_entities(\u0026mut self, doomed: \u0026[CatalogKey]) {\\n214\\t        for collection in doomed {\\n215\\t            self.purge_collection_entities(collection);\\n216\\t        }\\n217\\t    }\\n218\\t\\n219\\t    fn namespace_collection_keys(\u0026self, namespace: \u0026Namespace) -\u003e Vec\u003cCatalogKey\u003e {\\n220\\t        self.collections\\n221\\t            .iter()\\n222\\t            .filter(|key| key.namespace == *namespace)\\n223\\t            .cloned()\\n224\\t            .collect()\\n225\\t    }\\n226\\t\\n227\\t    fn database_collection_keys(\u0026self, database: \u0026str) -\u003e Vec\u003cCatalogKey\u003e {\\n228\\t        self.collections\\n229\\t            .iter()\\n230\\t            .filter(|key| key.namespace.database == database)\\n231\\t            .cloned()\\n232\\t            .collect()\\n233\\t    }\\n234\\t}\\n235\\t\\n236\\timpl StorageAdapter for MemoryStorageAdapter {\\n237\\t    fn resolve_collection_key(\\n238\\t        \u0026self,\\n239\\t        collection: \u0026CollectionId,\\n240\\t    ) -\u003e Result\u003cQualifiedCollectionId, AxonError\u003e {\\n241\\t        self.resolve_catalog_key(collection)\\n242\\t    }\\n243\\t\\n244\\t    fn get(\u0026self, collection: \u0026CollectionId, id: \u0026EntityId) -\u003e Result\u003cOption\u003cEntity\u003e, AxonError\u003e {\\n245\\t        let key = self.resolve_catalog_key(collection)?;\\n246\\t        Ok(self.data.get(\u0026key).and_then(|col| col.get(id)).cloned())\\n247\\t    }\\n248\\t\\n249\\t    fn put(\u0026mut self, entity: Entity) -\u003e Result\u003c(), AxonError\u003e {\\n250\\t        let key = self.resolve_catalog_key(\u0026entity.collection)?;\\n251\\t        let mut stored = entity;\\n252\\t        stored.collection = key.collection.clone();\\n253\\t        self.data\\n254\\t            .entry(key)\\n255\\t            .or_default()\\n256\\t            .insert(stored.id.clone(), stored);\\n257\\t        Ok(())\\n258\\t    }\\n259\\t\\n260\\t    fn delete(\u0026mut self, collection: \u0026CollectionId, id: \u0026EntityId) -\u003e Result\u003c(), AxonError\u003e {\\n261\\t        let key = self.resolve_catalog_key(collection)?;\\n262\\t        if let Some(col) = self.data.get_mut(\u0026key) {\\n263\\t            col.remove(id);\\n264\\t        }\\n265\\t        Ok(())\\n266\\t    }\\n267\\t\\n268\\t    fn count(\u0026self, collection: \u0026CollectionId) -\u003e Result\u003cusize, AxonError\u003e {\\n269\\t        let key = self.resolve_catalog_key(collection)?;\\n270\\t        Ok(self.data.get(\u0026key).map_or(0, |col| col.len()))\\n271\\t    }\\n272\\t\\n273\\t    fn range_scan(\\n274\\t        \u0026self,\\n275\\t        collection: \u0026CollectionId,\\n276\\t        start: Option\u003c\u0026EntityId\u003e,\\n277\\t        end: Option\u003c\u0026EntityId\u003e,\\n278\\t        limit: Option\u003cusize\u003e,\\n279\\t    ) -\u003e Result\u003cVec\u003cEntity\u003e, AxonError\u003e {\\n280\\t        let key = self.resolve_catalog_key(collection)?;\\n281\\t        let Some(col) = self.data.get(\u0026key) else {\\n282\\t            return Ok(vec![]);\\n283\\t        };\\n284\\t\\n285\\t        let mut entities: Vec\u003c\u0026Entity\u003e = col\\n286\\t            .values()\\n287\\t            .filter(|e| {\\n288\\t                start.map_or(true, |s| e.id.as_str() \u003e= s.as_str())\\n289\\t                    \u0026\u0026 end.map_or(true, |en| e.id.as_str() \u003c= en.as_str())\\n290\\t            })\\n291\\t            .collect();\\n292\\t\\n293\\t        entities.sort_by(|a, b| a.id.as_str().cmp(b.id.as_str()));\\n294\\t\\n295\\t        if let Some(n) = limit {\\n296\\t            entities.truncate(n);\\n297\\t        }\\n298\\t\\n299\\t        Ok(entities.into_iter().cloned().collect())\\n300\\t    }\\n301\\t\\n302\\t    fn compare_and_swap(\\n303\\t        \u0026mut self,\\n304\\t        entity: Entity,\\n305\\t        expected_version: u64,\\n306\\t    ) -\u003e Result\u003cEntity, AxonError\u003e {\\n307\\t        let key = self.resolve_catalog_key(\u0026entity.collection)?;\\n308\\t        let current = self\\n309\\t            .data\\n310\\t            .get(\u0026key)\\n311\\t            .and_then(|col| col.get(\u0026entity.id))\\n312\\t            .cloned();\\n313\\t\\n314\\t        match current.as_ref().map(|e| e.version) {\\n315\\t            Some(v) if v == expected_version =\u003e {}\\n316\\t            Some(actual) =\u003e {\\n317\\t                return Err(AxonError::ConflictingVersion {\\n318\\t                    expected: expected_version,\\n319\\t                    actual,\\n320\\t                    current_entity: current.map(Box::new),\\n321\\t                });\\n322\\t            }\\n323\\t            None =\u003e {\\n324\\t                return Err(AxonError::ConflictingVersion {\\n325\\t                    expected: expected_version,\\n326\\t                    actual: 0,\\n327\\t                    current_entity: None,\\n328\\t                });\\n329\\t            }\\n330\\t        }\\n331\\t\\n332\\t        let updated = Entity {\\n333\\t            collection: key.collection.clone(),\\n334\\t            version: expected_version + 1,\\n335\\t            ..entity\\n336\\t        };\\n337\\t\\n338\\t        self.data\\n339\\t            .entry(key)\\n340\\t            .or_default()\\n341\\t            .insert(updated.id.clone(), updated.clone());\\n342\\t\\n343\\t        Ok(updated)\\n344\\t    }\\n345\\t\\n346\\t    fn create_if_absent(\\n347\\t        \u0026mut self,\\n348\\t        entity: Entity,\\n349\\t        expected_absent_version: u64,\\n350\\t    ) -\u003e Result\u003cEntity, AxonError\u003e {\\n351\\t        let key = self.resolve_catalog_key(\u0026entity.collection)?;\\n352\\t        let current = self\\n353\\t            .data\\n354\\t            .get(\u0026key)\\n355\\t            .and_then(|col| col.get(\u0026entity.id))\\n356\\t            .cloned();\\n357\\t\\n358\\t        if let Some(current) = current {\\n359\\t            return Err(AxonError::ConflictingVersion {\\n360\\t                expected: expected_absent_version,\\n361\\t                actual: current.version,\\n362\\t                current_entity: Some(Box::new(current)),\\n363\\t            });\\n364\\t        }\\n365\\t\\n366\\t        let inserted = Entity {\\n367\\t            collection: key.collection.clone(),\\n368\\t            ..entity\\n369\\t        };\\n370\\t        self.data\\n371\\t            .entry(key)\\n372\\t            .or_default()\\n373\\t            .insert(inserted.id.clone(), inserted.clone());\\n374\\t        Ok(inserted)\\n375\\t    }\\n376\\t\\n377\\t    fn begin_tx(\u0026mut self) -\u003e Result\u003c(), AxonError\u003e {\\n378\\t        if self.tx_snapshot.is_some() {\\n379\\t            return Err(AxonError::Storage(\\\"transaction already active\\\".into()));\\n380\\t        }\\n381\\t        self.tx_snapshot = Some(TxSnapshot {\\n382\\t            data: self.data.clone(),\\n383\\t            schema_versions: self.schema_versions.clone(),\\n384\\t            collection_views: self.collection_views.clone(),\\n385\\t            collections: self.collections.clone(),\\n386\\t            databases: self.databases.clone(),\\n387\\t            namespaces: self.namespaces.clone(),\\n388\\t            indexes: self.indexes.clone(),\\n389\\t            compound_indexes: self.compound_indexes.clone(),\\n390\\t            numeric_ids: self.numeric_ids.clone(),\\n391\\t            links: self.links.clone(),\\n392\\t        });\\n393\\t        Ok(())\\n394\\t    }\\n395\\t\\n396\\t    fn commit_tx(\u0026mut self) -\u003e Result\u003c(), AxonError\u003e {\\n397\\t        if self.tx_snapshot.is_none() {\\n398\\t            return Err(AxonError::Storage(\\\"no active transaction\\\".into()));\\n399\\t        }\\n400\\t        self.tx_snapshot = None;\\n401\\t        Ok(())\\n402\\t    }\\n403\\t\\n404\\t    fn abort_tx(\u0026mut self) -\u003e Result\u003c(), AxonError\u003e {\\n405\\t        if let Some(snapshot) = self.tx_snapshot.take() {\\n406\\t            self.data = snapshot.data;\\n407\\t            self.schema_versions = snapshot.schema_versions;\\n408\\t            self.collection_views = snapshot.collection_views;\\n409\\t            self.collections = snapshot.collections;\\n410\\t            self.databases = snapshot.databases;\\n411\\t            self.namespaces = snapshot.namespaces;\\n412\\t            self.indexes = snapshot.indexes;\\n413\\t            self.compound_indexes = snapshot.compound_indexes;\\n414\\t            self.numeric_ids = snapshot.numeric_ids;\\n415\\t            self.links = snapshot.links;\\n416\\t        }\\n417\\t        Ok(())\\n418\\t    }\\n419\\t\\n420\\t    fn create_database(\u0026mut self, name: \u0026str) -\u003e Result\u003c(), AxonError\u003e {\\n421\\t        if !self.databases.insert(name.to_string()) {\\n422\\t            return Err(AxonError::AlreadyExists(format!(\\\"database '{name}'\\\")));\\n423\\t        }\\n424\\t        self.namespaces.insert(\\n425\\t            name.to_string(),\\n426\\t            BTreeSet::from([DEFAULT_SCHEMA.to_string()]),\\n427\\t        );\\n428\\t        Ok(())\\n429\\t    }\\n430\\t\\n431\\t    fn list_databases(\u0026self) -\u003e Result\u003cVec\u003cString\u003e, AxonError\u003e {\\n432\\t        Ok(self.databases.iter().cloned().collect())\\n433\\t    }\\n434\\t\\n435\\t    fn drop_database(\u0026mut self, name: \u0026str) -\u003e Result\u003c(), AxonError\u003e {\\n436\\t        if !self.databases.remove(name) {\\n437\\t            return Err(AxonError::NotFound(format!(\\\"database '{name}'\\\")));\\n438\\t        }\\n439\\t\\n440\\t        self.namespaces.remove(name);\\n441\\t        let doomed = self.database_collection_keys(name);\\n442\\t        self.purge_links_for_collections(\u0026doomed)?;\\n443\\t        self.purge_doomed_collection_entities(\u0026doomed);\\n444\\t        for key in doomed {\\n445\\t            self.remove_catalog_key(\u0026key);\\n446\\t        }\\n447\\t        Ok(())\\n448\\t    }\\n449\\t\\n450\\t    fn create_namespace(\u0026mut self, namespace: \u0026Namespace) -\u003e Result\u003c(), AxonError\u003e {\\n451\\t        let schemas = self\\n452\\t            .namespaces\\n453\\t            .get_mut(\u0026namespace.database)\\n454\\t            .ok_or_else(|| AxonError::NotFound(format!(\\\"database '{}'\\\", namespace.database)))?;\\n455\\t\\n456\\t        if !schemas.insert(namespace.schema.clone()) {\\n457\\t            return Err(AxonError::AlreadyExists(format!(\\\"namespace '{namespace}'\\\")));\\n458\\t        }\\n459\\t        Ok(())\\n460\\t    }\\n461\\t\\n462\\t    fn list_namespaces(\u0026self, database: \u0026str) -\u003e Result\u003cVec\u003cString\u003e, AxonError\u003e {\\n463\\t        match self.namespaces.get(database) {\\n464\\t            Some(schemas) =\u003e Ok(schemas.iter().cloned().collect()),\\n465\\t            None =\u003e Err(AxonError::NotFound(format!(\\\"database '{database}'\\\"))),\\n466\\t        }\\n467\\t    }\\n468\\t\\n469\\t    fn drop_namespace(\u0026mut self, namespace: \u0026Namespace) -\u003e Result\u003c(), AxonError\u003e {\\n470\\t        let schemas = self\\n471\\t            .namespaces\\n472\\t            .get_mut(\u0026namespace.database)\\n473\\t            .ok_or_else(|| AxonError::NotFound(format!(\\\"database '{}'\\\", namespace.database)))?;\\n474\\t\\n475\\t        if !schemas.remove(\u0026namespace.schema) {\\n476\\t            return Err(AxonError::NotFound(format!(\\\"namespace '{namespace}'\\\")));\\n477\\t        }\\n478\\t\\n479\\t        let doomed = self.namespace_collection_keys(namespace);\\n480\\t        self.purge_links_for_collections(\u0026doomed)?;\\n481\\t        self.purge_doomed_collection_entities(\u0026doomed);\\n482\\t        for key in doomed {\\n483\\t            self.remove_catalog_key(\u0026key);\\n484\\t        }\\n485\\t        Ok(())\\n486\\t    }\\n487\\t\\n488\\t    fn list_namespace_collections(\\n489\\t        \u0026self,\\n490\\t        namespace: \u0026Namespace,\\n491\\t    ) -\u003e Result\u003cVec\u003cCollectionId\u003e, AxonError\u003e {\\n492\\t        let schemas = self\\n493\\t            .namespaces\\n494\\t            .get(\u0026namespace.database)\\n495\\t            .ok_or_else(|| AxonError::NotFound(format!(\\\"database '{}'\\\", namespace.database)))?;\\n496\\t        if !schemas.contains(\u0026namespace.schema) {\\n497\\t            return Err(AxonError::NotFound(format!(\\\"namespace '{namespace}'\\\")));\\n498\\t        }\\n499\\t\\n500\\t        let mut collections: Vec\u003cCollectionId\u003e = self\\n501\\t            .collections\\n502\\t            .iter()\\n503\\t            .filter(|key| key.namespace == *namespace)\\n504\\t            .map(|key| key.collection.clone())\\n505\\t            .collect();\\n506\\t        collections.sort();\\n507\\t        Ok(collections)\\n508\\t    }\\n509\\t\\n510\\t    fn put_schema(\u0026mut self, schema: \u0026CollectionSchema) -\u003e Result\u003c(), AxonError\u003e {\\n511\\t        let key = self.resolve_catalog_key(\u0026schema.collection)?;\\n512\\t        let versions = self.schema_versions.entry(key).or_default();\\n513\\t        let next_version = versions.keys().last().map_or(1, |v| v + 1);\\n514\\t        let mut versioned = schema.clone();\\n515\\t        versioned.collection = schema\\n516\\t            .collection\\n517\\t            .as_str()\\n518\\t            .split('.')\\n519\\t            .next_back()\\n520\\t            .map(CollectionId::new)\\n521\\t            .unwrap_or_else(|| schema.collection.clone());\\n522\\t        versioned.version = next_version;\\n523\\t        versions.insert(next_version, (versioned, now_ns()));\\n524\\t        Ok(())\\n525\\t    }\\n526\\t\\n527\\t    fn get_schema(\u0026self, collection: \u0026CollectionId) -\u003e Result\u003cOption\u003cCollectionSchema\u003e, AxonError\u003e {\\n528\\t        let key = self.resolve_catalog_key(collection)?;\\n529\\t        Ok(self\\n530\\t            .schema_versions\\n531\\t            .get(\u0026key)\\n532\\t            .and_then(|versions| versions.values().last())\\n533\\t            .map(|(schema, _)| schema.clone()))\\n534\\t    }\\n535\\t\\n536\\t    fn get_schema_version(\\n537\\t        \u0026self,\\n538\\t        collection: \u0026CollectionId,\\n539\\t        version: u32,\\n540\\t    ) -\u003e Result\u003cOption\u003cCollectionSchema\u003e, AxonError\u003e {\\n541\\t        let key = self.resolve_catalog_key(collection)?;\\n542\\t        Ok(self\\n543\\t            .schema_versions\\n544\\t            .get(\u0026key)\\n545\\t            .and_then(|versions| versions.get(\u0026version))\\n546\\t            .map(|(schema, _)| schema.clone()))\\n547\\t    }\\n548\\t\\n549\\t    fn list_schema_versions(\\n550\\t        \u0026self,\\n551\\t        collection: \u0026CollectionId,\\n552\\t    ) -\u003e Result\u003cVec\u003c(u32, u64)\u003e, AxonError\u003e {\\n553\\t        let key = self.resolve_catalog_key(collection)?;\\n554\\t        Ok(self\\n555\\t            .schema_versions\\n556\\t          }\\n\\n    #[test]\\n    fn abort_tx_rolls_back_writes() {\\n        let mut s = store();\\n        s.put(entity(\\\"t-existing\\\"))\\n            .expect(\\\"test operation should succeed\\\");\\n\\n        s.begin_tx().expect(\\\"test operation should succeed\\\");\\n        s.put(entity(\\\"t-new\\\"))\\n            .expect(\\\"test operation should succeed\\\");\\n        s.delete(\u0026tasks(), \u0026EntityId::new(\\\"t-existing\\\"))\\n            .expect(\\\"test operation should succeed\\\");\\n        s.abort_tx().expect(\\\"test operation should succeed\\\");\\n\\n        assert!(s\\n            .get(\u0026tasks(), \u0026EntityId::new(\\\"t-new\\\"))\\n            .expect(\\\"test operation should succeed\\\")\\n            .is_none());\\n        assert!(s\\n            .get(\u0026tasks(), \u0026EntityId::new(\\\"t-existing\\\"))\\n            .expect(\\\"test operation should succeed\\\")\\n            .is_some());\\n    }\\n\\n    #[test]\\n    fn begin_tx_rejects_nested_begin() {\\n        let mut s = store();\\n        s.begin_tx().expect(\\\"test operation should succeed\\\");\\n        assert!(s.begin_tx().is_err());\\n        s.abort_tx().expect(\\\"test operation should succeed\\\");\\n    }\\n\\n    #[test]\\n    fn commit_tx_requires_active_transaction() {\\n        let mut s = store();\\n        assert!(s.commit_tx().is_err());\\n    }\\n\\n    #[test]\\n    fn abort_tx_without_active_tx_is_noop() {\\n        let mut s = store();\\n        s.abort_tx().expect(\\\"test operation should succeed\\\");\\n    }\\n\\n    // ── Schema persistence ───────────────────────────────────────────────────\\n\\n    #[test]\\n    fn put_get_schema_roundtrip() {\\n        use axon_schema::schema::CollectionSchema;\\n        let mut s = store();\\n        let col = tasks();\\n        let schema = CollectionSchema {\\n            collection: col.clone(),\\n            description: Some(\\\"test schema\\\".into()),\\n            version: 99, // ignored — auto-increment assigns v1\\n            entity_schema: Some(json!({\\\"type\\\": \\\"object\\\"})),\\n            link_types: Default::default(),\\n            gates: Default::default(),\\n            validation_rules: Default::default(),\\n            indexes: Default::default(),\\n            compound_indexes: Default::default(),\\n            lifecycles: Default::default(),\\n        };\\n\\n        s.put_schema(\u0026schema)\\n            .expect(\\\"test operation should succeed\\\");\\n\\n        let retrieved = s.get_schema(\u0026col).expect(\\\"test operation should succeed\\\");\\n        assert!(retrieved.is_some());\\n        let retrieved = retrieved.expect(\\\"test operation should succeed\\\");\\n        assert_eq!(retrieved.collection, col);\\n        assert_eq!(retrieved.version, 1); // auto-incremented\\n        assert_eq!(retrieved.description.as_deref(), Some(\\\"test schema\\\"));\\n    }\\n\\n    #[test]\\n    fn get_schema_missing_returns_none() {\\n        let s = store();\\n        assert!(s\\n            .get_schema(\u0026tasks())\\n            .expect(\\\"test operation should succeed\\\")\\n            .is_none());\\n    }\\n\\n    #[test]\\n    fn put_schema_overwrites_previous() {\\n        use axon_schema::schema::CollectionSchema;\\n        let mut s = store();\\n        let col = tasks();\\n\\n        let v1 = CollectionSchema {\\n            collection: col.clone(),\\n            description: None,\\n            version: 1,\\n            entity_schema: None,\\n            link_types: Default::default(),\\n            gates: Default::default(),\\n            validation_rules: Default::default(),\\n            indexes: Default::default(),\\n            compound_indexes: Default::default(),\\n            lifecycles: Default::default(),\\n        };\\n        let v2 = CollectionSchema {\\n            collection: col.clone(),\\n            description: Some(\\\"v2\\\".into()),\\n            version: 2,\\n            entity_schema: None,\\n            link_types: Default::default(),\\n            gates: Default::default(),\\n            validation_rules: Default::default(),\\n            indexes: Default::default(),\\n            compound_indexes: Default::default(),\\n            lifecycles: Default::default(),\\n        };\\n\\n        s.put_schema(\u0026v1).expect(\\\"test operation should succeed\\\");\\n        s.put_schema(\u0026v2).expect(\\\"test operation should succeed\\\");\\n\\n        let retrieved = s\\n            .get_schema(\u0026col)\\n            .expect(\\\"test operation should succeed\\\")\\n            .expect(\\\"test operation should succeed\\\");\\n        assert_eq!(\\n            retrieved.version, 2,\\n            \\\"second put_schema must overwrite the first\\\"\\n        );\\n    }\\n\\n    #[test]\\n    fn delete_schema_removes_it() {\\n        use axon_schema::schema::CollectionSchema;\\n        let mut s = store();\\n        let col = tasks();\\n        let schema = CollectionSchema {\\n            collection: col.clone(),\\n            description: None,\\n            version: 1,\\n            entity_schema: None,\\n            link_types: Default::default(),\\n            gates: Default::default(),\\n            validation_rules: Default::default(),\\n            indexes: Default::default(),\\n            compound_indexes: Default::default(),\\n            lifecycles: Default::default(),\\n        };\\n\\n        s.put_schema(\u0026schema)\\n            .expect(\\\"test operation should succeed\\\");\\n        assert!(s\\n            .get_schema(\u0026col)\\n            .expect(\\\"test operation should succeed\\\")\\n            .is_some());\\n\\n        s.delete_schema(\u0026col)\\n            .expect(\\\"test operation should succeed\\\");\\n        assert!(s\\n            .get_schema(\u0026col)\\n            .expect(\\\"test operation should succeed\\\")\\n            .is_none());\\n    }\\n\\n    #[test]\\n    fn qualified_schema_write_is_readable_via_bare_unique_collection() {\\n        let mut s = store();\\n        let qualified = CollectionId::new(\\\"prod.billing.invoices\\\");\\n        let (billing, invoices) = register_unique_namespaced_collection(\u0026mut s, \u0026qualified);\\n\\n        let v1 = CollectionSchema {\\n            collection: qualified.clone(),\\n            description: Some(\\\"v1\\\".into()),\\n            version: 99,\\n            entity_schema: Some(\\n                json!({\\\"type\\\": \\\"object\\\", \\\"properties\\\": {\\\"title\\\": {\\\"type\\\": \\\"string\\\"}}}),\\n            ),\\n            link_types: Default::default(),\\n            gates: Default::default(),\\n            validation_rules: Default::default(),\\n            indexes: Default::default(),\\n            compound_indexes: Default::default(),\\n            lifecycles: Default::default(),\\n        };\\n        let v2 = CollectionSchema {\\n            collection: qualified,\\n            description: Some(\\\"v2\\\".into()),\\n            version: 100,\\n            entity_schema: Some(\\n                json!({\\\"type\\\": \\\"object\\\", \\\"properties\\\": {\\\"amount\\\": {\\\"type\\\": \\\"number\\\"}}}),\\n            ),\\n            link_types: Default::default(),\\n            gates: Default::default(),\\n            validation_rules: Default::default(),\\n            indexes: Default::default(),\\n            compound_indexes: Default::default(),\\n            lifecycles: Default::default(),\\n        };\\n\\n        s.put_schema(\u0026v1).expect(\\\"schema v1 put should succeed\\\");\\n        s.put_schema(\u0026v2).expect(\\\"schema v2 put should succeed\\\");\\n\\n        let stored_collections: Vec\u003cString\u003e = {\\n            let conn = s.conn.lock().expect(\\\"lock\\\");\\n            let mut stmt = conn\\n                .prepare(\\n                    \\\"SELECT collection FROM schema_versions\\n                     WHERE database_name = ?1 AND schema_name = ?2\\n                     ORDER BY version ASC\\\",\\n                )\\n                .expect(\\\"schema version query should prepare\\\");\\n            stmt.query_map(\\n                params![billing.database.as_str(), billing.schema.as_str()],\\n                |row| row.get::\u003c_, String\u003e(0),\\n            )\\n            .expect(\\\"schema version query should succeed\\\")\\n            .collect::\u003cResult\u003cVec\u003c_\u003e, _\u003e\u003e()\\n            .expect(\\\"schema version rows should decode\\\")\\n        };\\n        assert_eq!(\\n            stored_collections,\\n            vec![\\\"invoices\\\".to_string(), \\\"invoices\\\".to_string()]\\n        );\\n\\n        let latest = s\\n            .get_schema(\u0026invoices)\\n            .expect(\\\"latest schema lookup should succeed\\\")\\n            .expect(\\\"latest schema should exist\\\");\\n        assert_eq!(latest.collection, invoices);\\n        assert_eq!(latest.version, 2);\\n        assert_eq!(latest.description.as_deref(), Some(\\\"v2\\\"));\\n\\n        let version_one = s\\n            .get_schema_version(\u0026invoices, 1)\\n            .expect(\\\"versioned schema lookup should succeed\\\")\\n            .expect(\\\"schema version one should exist\\\");\\n        assert_eq!(version_one.collection, invoices);\\n        assert_eq!(version_one.description.as_deref(), Some(\\\"v1\\\"));\\n\\n        assert_eq!(\\n            s.list_schema_versions(\u0026invoices)\\n                .expect(\\\"schema version list should succeed\\\")\\n                .into_iter()\\n                .map(|(version, _)| version)\\n                .collect::\u003cVec\u003c_\u003e\u003e(),\\n            vec![1, 2]\\n        );\\n    }\\n\\n    #[test]\\n    fn qualified_collection_view_write_is_readable_via_bare_unique_collection() {\\n        let mut s = store();\\n        let qualified = CollectionId::new(\\\"prod.billing.invoices\\\");\\n        let (billing, invoices) = register_unique_namespaced_collection(\u0026mut s, \u0026qualified);\\n\\n        let stored = s\\n            .put_collection_view(\u0026CollectionView::new(qualified, \\\"# {{title}}\\\"))\\n            .expect(\\\"qualified collection view put should succeed\\\");\\n        assert_eq!(stored.collection, invoices);\\n        assert_eq!(stored.version, 1);\\n\\n        let stored_collection: String = s\\n            .conn\\n            .lock()\\n            .expect(\\\"lock\\\")\\n            .query_row(\\n                \\\"SELECT collection FROM collection_views\\n                 WHERE database_name = ?1 AND schema_name = ?2\\\",\\n                params![billing.database.as_str(), billing.schema.as_str()],\\n                |row| row.get(0),\\n            )\\n            .