// TestMain clears all GIT_* environment variables before running tests so
// that tests invoking git commands operate on their own temp-dir repositories
// rather than any repository inherited from a hook invocation (e.g. GIT_DIR
// set by lefthook during pre-commit). Prefix scrub is important — lefthook
// sets GIT_AUTHOR_NAME, GIT_COMMITTER_EMAIL, GIT_CONFIG_PARAMETERS etc. that
// also leak into test subprocesses and corrupt the shared repo config.
func TestMain(m *testing.M) {
	for _, kv := range os.Environ() {
		if strings.HasPrefix(kv, "GIT_") {
			if idx := strings.IndexByte(kv, '='); idx >= 0 {
				_ = os.Unsetenv(kv[:idx])
			}
		}
	}
	// Keep cmd tests hermetic. Background update checks can outlive a single
	// test and write into another test's temp HOME/TMPDIR, which makes temp-dir
	// cleanup flaky under the full suite.
	_ = os.Setenv("DDX_DISABLE_UPDATE_CHECK", "1")
	cleanupTemp := isolateCmdTestTempRoot()
	code := m.Run()
	cleanupTemp()
	os.Exit(code)
}

func isolateCmdTestTempRoot() func() {
	tempRoot, err := os.MkdirTemp("", "ddx-cmd-tests-*")
	if err != nil {
		return func() {}
	}
	oldTmpDir, hadTmpDir := os.LookupEnv("TMPDIR")
	oldTmp, hadTmp := os.LookupEnv("TMP")
	oldXDG, hadXDG := os.LookupEnv("XDG_DATA_HOME")
	oldHome, hadHome := os.LookupEnv("HOME")
	homeDir := filepath.Join(tempRoot, "home")
	_ = os.MkdirAll(homeDir, 0o755)
	_ = os.Setenv("TMPDIR", tempRoot)
	_ = os.Setenv("TMP", tempRoot)
	_ = os.Setenv("XDG_DATA_HOME", filepath.Join(tempRoot, "xdg"))
	_ = os.Setenv("HOME", homeDir)
	return func() {
		if hadTmpDir {
			_ = os.Setenv("TMPDIR", oldTmpDir)
		} else {
			_ = os.Unsetenv("TMPDIR")
		}
		if hadTmp {
			_ = os.Setenv("TMP", oldTmp)
		} else {
			_ = os.Unsetenv("TMP")
		}
		if hadXDG {
			_ = os.Setenv("XDG_DATA_HOME", oldXDG)
		} else {
			_ = os.Unsetenv("XDG_DATA_HOME")
		}
		if hadHome {
			_ = os.Setenv("HOME", oldHome)
		} else {
			_ = os.Unsetenv("HOME")
		}
		_ = os.RemoveAll(tempRoot)
	}
}

// buildTestLibraryFixture creates a per-test bare git repository that mimics
// the upstream ddx library. The repo lives under t.TempDir() and is cleaned up
// automatically with the test.
func buildTestLibraryFixture(t *testing.T) string {
	t.Helper()

	_, filename, _, _ := runtime.Caller(0)
	cmdDir := filepath.Dir(filename)
	fixtureDir := filepath.Join(cmdDir, "..", "test", "fixtures", "ddx-library")
	fixtureDir, err := filepath.Abs(fixtureDir)
	require.NoError(t, err)

	root := t.TempDir()
	workingRepo := filepath.Join(root, ".test-library")
	bareRepo := filepath.Join(root, ".test-library.git")

	require.NoError(t, os.MkdirAll(workingRepo, 0o755))
	require.NoError(t, syncDirectory(fixtureDir, workingRepo))

	cmds := []struct {
		args []string
		dir  string
	}{
		{[]string{"git", "init", "-b", "master"}, workingRepo},
		{[]string{"git", "config", "user.email", "test@example.com"}, workingRepo},
		{[]string{"git", "config", "user.name", "Test User"}, workingRepo},
		{[]string{"git", "add", "."}, workingRepo},
		{[]string{"git", "commit", "--allow-empty", "-m", "Test fixture"}, workingRepo},
		{[]string{"git", "init", "--bare", bareRepo}, ""},
		{[]string{"git", "remote", "add", "origin", bareRepo}, workingRepo},
		{[]string{"git", "push", "origin", "master"}, workingRepo},
	}

	for _, c := range cmds {
		cmd := exec.Command(c.args[0], c.args[1:]...)
		if c.dir != "" {
			cmd.Dir = c.dir
		}
		cmd.Env = gitpkg.CleanEnv()
		output, err := cmd.CombinedOutput()
		require.NoErrorf(t, err, "failed to run %v\nOutput: %s", c.args, output)
	}

	return bareRepo
}

// syncDirectory copies files from src to dst, preserving directory structure
func syncDirectory(src, dst string) error {
	return filepath.Walk(src, func(path string, info os.FileInfo, err error) error {
		if err != nil {
			return err
		}

		// Skip .git directories from source
		if info.IsDir() && info.Name() == ".git" {
			return filepath.SkipDir
		}

		// Calculate relative path
		relPath, err := filepath.Rel(src, path)
		if err != nil {
			return err
		}

		dstPath := filepath.Join(dst, relPath)

		if info.IsDir() {
			return os.MkdirAll(dstPath, info.Mode())
		}

		// Copy file
		srcFile, err := os.Open(path)
		if err != nil {
			return err
		}
		defer func() { _ = srcFile.Close() }()

		dstFile, err := os.Create(dstPath)
		if err != nil {
			return err
		}
		defer func() { _ = dstFile.Close() }()

		if _, err := dstFile.ReadFrom(srcFile); err != nil {
			return err
		}

		return os.Chmod(dstPath, info.Mode())
	})
}

// TestEnvironment provides isolated testing environment for .ddx/config.yaml
type TestEnvironment struct {
	Dir            string
	ConfigPath     string
	LibraryPath    string
	TestLibraryURL string

	t.Helper()
	tempDir := t.TempDir()
	return NewCommandFactory(tempDir)
}

// NewTestRootCommandWithDir creates a test command with a specific working directory
// Use this when your test needs to operate in a specific directory.
func NewTestRootCommandWithDir(dir string) *CommandFactory {
	return NewCommandFactory(dir)
}

// executeCommand is a helper to execute commands with captured output (legacy compatibility)
// New tests should use TestEnvironment.RunCommand() instead
func executeCommand(root *cobra.Command, args ...string) (output string, err error) {
	buf := new(bytes.Buffer)
	root.SetOut(buf)
	root.SetErr(buf)
	root.SetArgs(args)

	err = root.Execute()
	return buf.String(), err
}

package bead

import (
	"bufio"
	"bytes"
	"encoding/json"
	"fmt"
	"os"
	"path/filepath"
	"sort"
	"strings"
	"time"
)

// DoctorFinding reports a single field that exceeds MaxFieldBytes on a single
// bead row, or a dependency edge that points back into the bead's parent
// chain. One bead can produce multiple findings (description + acceptance +
// event bodies, etc.).
type DoctorFinding struct {
	Kind            string   `json:"kind"`
	BeadID          string   `json:"bead_id"`
	FieldPath       string   `json:"field_path,omitempty"` // "description", "acceptance", "notes", "events[N].body", "events[N].summary", or "dependencies[N].depends_on_id"
	DependencyIndex int      `json:"dependency_index,omitempty"`
	DependsOnID     string   `json:"depends_on_id,omitempty"`
	ParentChain     []string `json:"parent_chain,omitempty"`
	SizeBytes       int      `json:"size_bytes,omitempty"`
	SampleHead      string   `json:"sample_head,omitempty"` // first 80 bytes for visual identification
}

// DoctorReport is the output of BeadDoctor — an ordered list of findings.
type DoctorReport struct {
	Path     string
	Findings []DoctorFinding
}

const (
	DoctorFindingOversizedField       = "oversized_field"
	DoctorFindingParentAncestorInDeps = "parent_ancestor_in_deps"
)

// Clean is true when there are no findings (i.e. all bead fields fit).
func (r DoctorReport) Clean() bool { return len(r.Findings) == 0 }

// BeadDoctor scans a beads.jsonl file and returns every field that exceeds
// MaxFieldBytes plus any dependency edges that point back into a bead's
// parent chain. Parses each line best-effort; lines that fail to parse are
// reported as a single finding with FieldPath="line" and the raw line as the
// sample.
func BeadDoctor(path string) (DoctorReport, error) {
	report := DoctorReport{Path: path}
	f, err := os.Open(path)
	if err != nil {
		return report, err
	}
	defer f.Close()

	scanner := bufio.NewScanner(f)
	scanner.Buffer(make([]byte, 0, 64*1024), 16*1024*1024)
	lineNo := 0
	type parsedRow struct {
		id     string
		parent string
		deps   []DoctorFinding
	}
	parsed := make([]parsedRow, 0, 64)
	for scanner.Scan() {
		lineNo++
		line := bytes.TrimSpace(scanner.Bytes())
		if len(line) == 0 {
			continue
		}
		var raw map[string]any
		if err := json.Unmarshal(line, &raw); err != nil {
			report.Findings = append(report.Findings, DoctorFinding{
				Kind:       DoctorFindingOversizedField,
				BeadID:     fmt.Sprintf("line %d (unparseable)", lineNo),
				FieldPath:  "line",
				SizeBytes:  len(line),
				SampleHead: firstN(string(line), 80),
			})
			continue
		}
		id, _ := raw["id"].(string)
		parent, _ := raw["parent"].(string)
		row := parsedRow{id: id, parent: parent}
		for _, field := range []string{"description", "acceptance", "notes"} {
			if s, ok := raw[field].(string); ok && len(s) > MaxFieldBytes {
				report.Findings = append(report.Findings, DoctorFinding{
					Kind:       DoctorFindingOversizedField,
					BeadID:     id,
					FieldPath:  field,
					SizeBytes:  len(s),
					SampleHead: firstN(s, 80),
				})
			}
		}
		if events, ok := raw["events"].([]any); ok {
			for i, evRaw := range events {
				ev, _ := evRaw.(map[string]any)
				if ev == nil {
					continue
				}
				for _, field := range []string{"body", "summary"} {
					if s, ok := ev[field].(string); ok && len(s) > MaxFieldBytes {
						report.Findings = append(report.Findings, DoctorFinding{
							Kind:       DoctorFindingOversizedField,
							BeadID:     id,
							FieldPath:  fmt.Sprintf("events[%d].%s", i, field),
							SizeBytes:  len(s),
							SampleHead: firstN(s, 80),
						})
					}
				}
			}
		}
		if deps, ok := raw["dependencies"].([]any); ok {
			for i, depRaw := range deps {
				dep, _ := depRaw.(map[string]any)
				if dep == nil {
					continue
				}
				target, _ := dep["depends_on_id"].(string)
				if target == "" {
					continue
				}
				row.deps = append(row.deps, DoctorFinding{
					FieldPath:       fmt.Sprintf("dependencies[%d].depends_on_id", i),
					DependencyIndex: i,
					DependsOnID:     target,
				})
			}
		}
		parsed = append(parsed, row)
	}
	if err := scanner.Err(); err != nil {
		return report, fmt.Errorf("bead doctor: scanner: %w", err)
	}

	byID := make(map[string]*Bead, len(parsed))
	for i := range parsed {
		if parsed[i].id == "" {
			continue
		}
		byID[parsed[i].id] = &Bead{ID: parsed[i].id, Parent: parsed[i].parent}
	}
	for _, row := range parsed {
		if row.id == "" || row.parent == "" {
			continue
		}
		parentChain, _ := beadParentChain(byID, row.parent)
		if len(parentChain) == 0 {
			continue
		}
		for _, dep := range row.deps {
			for _, ancestorID := range parentChain {
				if ancestorID != dep.DependsOnID {
					continue
				}
				report.Findings = append(report.Findings, DoctorFinding{
					Kind:            DoctorFindingParentAncestorInDeps,
					BeadID:          row.id,
					FieldPath:       dep.FieldPath,
					DependencyIndex: dep.DependencyIndex,
					DependsOnID:     dep.DependsOnID,
					ParentChain:     append([]string(nil), parentChain...),
				})
				break
			}
		}
	}
	sort.SliceStable(report.Findings, func(i, j int) bool {
		if report.Findings[i].BeadID == report.Findings[j].BeadID {
			if report.Findings[i].Kind == report.Findings[j].Kind {
				switch report.Findings[i].Kind {
				case DoctorFindingParentAncestorInDeps:
					if report.Findings[i].DependencyIndex == report.Findings[j].DependencyIndex {
						return report.Findings[i].DependsOnID < report.Findings[j].DependsOnID
					}
					return report.Findings[i].DependencyIndex < report.Findings[j].DependencyIndex
				default:
					return report.Findings[i].FieldPath < report.Findings[j].FieldPath
				}
			}
			return report.Findings[i].Kind < report.Findings[j].Kind
		}
		return report.Findings[i].BeadID < report.Findings[j].BeadID
	})
	return report, nil
}

// BeadDoctorFix rewrites oversized fields on disk. Behavior:
//
//  1. If the file is already clean, returns the empty report without
//     touching anything.
//  2. Otherwise writes a timestamped backup under .ddx/backups/ before any
//     mutation; errors if the backup write fails.
//  3. Truncates oversized fields via capFieldBytes (head+tail+marker), then
//     writes full overflow content to
//     .ddx/executions/<bead-id>/repair-<timestamp>/<field>.log so the
//     original payload remains auditable.
//  4. Appends a repair event to each rewritten bead (kind="repair", actor=
//     "ddx bead doctor").
//  5. Returns the report of findings that were remediated.
//
// Idempotent: a second call finds no offending fields and returns a clean
// report without writing anything.
func BeadDoctorFix(path string, now func() time.Time) (DoctorReport, error) {
	if now == nil {
		now = time.Now
	}
	report, err := BeadDoctor(path)
	if err != nil {
		return report, err
	}
	if report.Clean() {
		return report, nil
	}

	ddxDir := filepath.Dir(path)
	ts := now().UTC().Format("20060102T150405")

	ts := now().UTC().Format("20060102T150405")

	backupDir := filepath.Join(ddxDir, "backups")
	if err := os.MkdirAll(backupDir, 0o755); err != nil {
		return report, fmt.Errorf("bead doctor: mkdir backup dir: %w", err)
	}
	backupPath := filepath.Join(backupDir, fmt.Sprintf("beads-%s.jsonl", ts))
	src, err := os.ReadFile(path)
	if err != nil {
		return report, fmt.Errorf("bead doctor: read source: %w", err)
	}
	if err := os.WriteFile(backupPath, src, 0o644); err != nil {
		return report, fmt.Errorf("bead doctor: write backup %s: %w", backupPath, err)
	}

	// Per-bead rewrite: parse each line, repair it, write it back.
	findingsByBead := make(map[string][]DoctorFinding)
	for _, f := range report.Findings {
		findingsByBead[f.BeadID] = append(findingsByBead[f.BeadID], f)
	}

	lines := bytes.Split(src, []byte{'\n'})
	var out bytes.Buffer
	for _, line := range lines {
		trimmed := bytes.TrimSpace(line)
		if len(trimmed) == 0 {
			out.Write(line)
			out.WriteByte('\n')
			continue
		}
		var raw map[string]any
		if err := json.Unmarshal(trimmed, &raw); err != nil {
			// Leave unparseable lines alone; the doctor report flagged them
			// but we cannot safely rewrite what we cannot parse.
			out.Write(line)
			out.WriteByte('\n')
			continue
		}
		id, _ := raw["id"].(string)
		beadFindings := findingsByBead[id]
		if len(beadFindings) == 0 {
			out.Write(trimmed)
			out.WriteByte('\n')
			continue
		}

		repairDir := filepath.Join(ddxDir, "executions", id, "repair-"+ts)
		if err := os.MkdirAll(repairDir, 0o755); err != nil {
			return report, fmt.Errorf("bead doctor: mkdir repair dir for %s: %w", id, err)
		}
		repaired := repairBead(raw, beadFindings, repairDir, ddxDir, now().UTC())
		encoded, err := json.Marshal(repaired)
		if err != nil {
			return report, fmt.Errorf("bead doctor: re-encode %s: %w", id, err)
		}
		out.Write(encoded)
		out.WriteByte('\n')
	}

	// Trim trailing newline if the source didn't have one.
	written := out.Bytes()
	if !bytes.HasSuffix(src, []byte{'\n'}) && bytes.HasSuffix(written, []byte{'\n'}) {
		written = written[:len(written)-1]
	}

	if err := os.WriteFile(path, written, 0o644); err != nil {
		return report, fmt.Errorf("bead doctor: write repaired %s: %w", path, err)
	}
	return report, nil
}

// repairBead applies per-field truncation + artifact sidecar writes. Updates
// raw in place and returns it for convenience.
func repairBead(raw map[string]any, findings []DoctorFinding, repairDir, ddxDir string, ts time.Time) map[string]any {
	changeRefs := make([]string, 0, len(findings))
	depFindings := make([]DoctorFinding, 0, len(findings))
	for _, f := range findings {
		switch f.Kind {
		case DoctorFindingOversizedField:
			ref := applyFieldRepair(raw, f, repairDir, ddxDir)
			if ref != "" {
				changeRefs = append(changeRefs, f.FieldPath+"→"+ref)
			}
		case DoctorFindingParentAncestorInDeps:
			depFindings = append(depFindings, f)
		}
	}
	sort.SliceStable(depFindings, func(i, j int) bool {
		if depFindings[i].DependencyIndex == depFindings[j].DependencyIndex {
			return depFindings[i].DependsOnID < depFindings[j].DependsOnID
		}
		return depFindings[i].DependencyIndex > depFindings[j].DependencyIndex
	})
	for _, f := range depFindings {
		if ref := applyParentAncestorDepRepair(raw, f); ref != "" {
			changeRefs = append(changeRefs, ref)
		}
	}

	if len(changeRefs) == 0 {
		return raw
	}

	events, _ := raw["events"].([]any)
	summaryParts := make([]string, 0, 2)
	fieldCount := 0
	depCount := 0
	for _, f := range findings {
		switch f.Kind {
		case DoctorFindingOversizedField:
			fieldCount++
		case DoctorFindingParentAncestorInDeps:
			depCount++
		}
	}
	if fieldCount > 0 {
		summaryParts = append(summaryParts, fmt.Sprintf("field cap (%d bytes) enforced: %d field(s) truncated", MaxFieldBytes, fieldCount))
	}
	if depCount > 0 {
		summaryParts = append(summaryParts, fmt.Sprintf("parent-ancestor dependency guard enforced: %d edge(s) removed", depCount))
	}
	events = append(events, map[string]any{
		"kind":       "repair",
		"summary":    strings.Join(summaryParts, "; "),
		"body":       strings.Join(changeRefs, "\n"),
		"actor":      "ddx bead doctor",
		"source":     "ddx bead doctor --fix",
		"created_at": ts.Format(time.RFC3339Nano),
	})
	raw["events"] = events
	raw["updated_at"] = ts.Format(time.RFC3339Nano)
	return raw
}

// applyFieldRepair replaces raw[field] with a capped version and writes the
// full content to an artifact path. Returns the repair-relative artifact
// path (for the repair event summary) or "" if the path cannot be resolved.
func applyFieldRepair(raw map[string]any, f DoctorFinding, repairDir, ddxDir string) string {
	original, ok := pickField(raw, f.FieldPath)
	if !ok {
		return ""
	}
	artifactName := strings.ReplaceAll(f.FieldPath, "[", "_")
	artifactName = strings.ReplaceAll(artifactName, "]", "")
	artifactName = strings.ReplaceAll(artifactName, ".", "_") + ".log"
	artifactPath := filepath.Join(repairDir, artifactName)
	if err := os.WriteFile(artifactPath, []byte(original), 0o644); err != nil {
		return ""
	}
	rel, err := filepath.Rel(filepath.Dir(ddxDir), artifactPath)
	if err != nil {
		rel = artifactPath
	}
	// capFieldBytes already yields a value at or below MaxFieldBytes. Don't
	// append the artifact reference to the field itself — that would push it
	// back over the cap and defeat idempotency. The repair event body
	// records the field→artifact mapping for audit.
	setField(raw, f.FieldPath, capFieldBytes(original))
	return rel
}


